import os, json, itertools, importlib.util, collections, re
print('PEFT_AVAILABLE', importlib.util.find_spec('peft') is not None)
print('BITSANDBYTES_AVAILABLE', importlib.util.find_spec('bitsandbytes') is not None)
print('TRL_AVAILABLE', importlib.util.find_spec('trl') is not None)
for path in ['model.py','predict.py','train.py']:
    print('\n###', path)
    txt=open(path).read().splitlines()
    for i,line in enumerate(txt,1):
        if i<=260:
            print(f'{i:03d}: {line[:180]}')
print('\n### dataset stats')
for split in ['unified_train.jsonl','unified_val.jsonl']:
    rows=[json.loads(l) for l in open('/data/'+split) if l.strip()]
    c=collections.Counter(('bbox' if r.get('target_bbox') else '')+('point' if r.get('target_point') else '') for r in rows)
    typ=collections.Counter(r.get('type','') for r in rows)
    sizes=collections.Counter((r['image_width'],r['image_height']) for r in rows)
    print(split, 'n', len(rows), 'modalities', dict(c), 'types', dict(typ), 'top_sizes', sizes.most_common(8))
    for r in rows[:3]:
        print(json.dumps({k:r.get(k) for k in ['id','image_path','instruction','target_bbox','target_point','image_width','image_height','type']}, ensure_ascii=False))
print('\n### val logs sample')
for log in ['logs/val_eval_qwen_base.jsonl','logs/val_eval_rescaled.jsonl','logs/val_eval.jsonl']:
    if os.path.exists(log):
        print('LOG', log)
        with open(log) as f:
            for j,l in zip(range(6), f):
                try:
                    o=json.loads(l)
                    print(json.dumps({k:o.get(k) for k in ['id','instruction','raw','pred','target_bbox','target_point','metric','ok']}, ensure_ascii=False)[:1000])
                except Exception as e:
                    print(l[:500])
